def test_AC_05_phase_AB_sequential_same_dirty_repo_primary():
    """
    PRIMARY AC-05 test (codex finding #4): single synthetic dirty repo, run
    Phase A blocked-bulk first, assert tree still dirty + no push-gate token +
    no Step 7 marker, then run Phase B non-bulk fallback on the SAME repo and
    assert real commit + canonical push-gate token + Step 7 dispatch marker.

    This is the closest a pytest fixture can come to invoking /commit
    end-to-end. The Claude orchestrator (LLM-driven slash command) is
    replaced by:
      - Phase A: direct invocation of scripts/write-bulk-commit-sentinel.py
        (the production script that /commit Step 5 invokes in --bulk mode).
      - Phase B: direct invocation of git plumbing (mirroring changelog-analyst
        Phase 5 commit creation) + push-gate write at canonical path (mirroring
        changelog-analyst Phase 6) + scripts/step7-spec-continue.py (the
        reference embodiment of /commit Step 7 selection + trace).

    The LLM-driven changelog-analyst dispatch (Step 6) is simulated via direct
    git-plumbing because (a) changelog-analyst is a Claude Code subagent that
    cannot be invoked from a pytest subprocess and (b) the AC-05 SUCCESS
    SIGNAL — push-gate token written + Step 7 marker observed — is verified at
    the same artifact boundary.
    """
    with tempfile.TemporaryDirectory(prefix="ac05-AB-") as tmp:
        tmp_root = pathlib.Path(tmp)
        repo_root = tmp_root / "synthetic-repo"
        repo_root.mkdir()
        dev_docs_root = tmp_root / "docs" / "dev"
        specs_dir = dev_docs_root / "specs"
        specs_dir.mkdir(parents=True, exist_ok=True)
        task_id = "20260524-205206-phaseAB"

        # Initialize repo + dirty file
        initial_sha = _init_synthetic_repo(repo_root)

        # ----- Phase A: blocked /commit --bulk on dirty tree -----
        fake_sid = f"phaseAB-{uuid.uuid4().hex[:8]}"
        # write-bulk-commit-sentinel.py override validator requires /tmp/
        # rooted path with a whitelisted basename prefix (see scripts/
        # write-bulk-commit-sentinel.py lines ~80-100).
        bulk_override = f"/tmp/claude-bulk-test-flag-AC05-AB-{fake_sid}.flag"
        if os.path.exists(bulk_override):
            os.unlink(bulk_override)
        assert not os.path.exists(bulk_override)
        sentinel_script = REPO_ROOT / "scripts" / "write-bulk-commit-sentinel.py"
        env_a = os.environ.copy()
        env_a["CLAUDE_SESSION_ID"] = fake_sid
        env_a["CLAUDE_BULK_AUTH_FLAG_PATH_OVERRIDE"] = bulk_override
        env_a["COMMIT_STEP7_TRACE"] = "1"
        proc_a = subprocess.run(
            [sys.executable, str(sentinel_script), "--output-dir", tmp],
            capture_output=True, text=True, env=env_a, timeout=10,
        )
        # Phase A assertions
        assert proc_a.returncode != 0, (
            "Phase A: bulk-sentinel script must reject when auth flag absent"
        )
        assert "BULK mode requires explicit user authorization" in proc_a.stderr
        # Tree still dirty (no commit happened)
        head_after_a = subprocess.run(
            ["git", "-C", str(repo_root), "rev-parse", "HEAD"],
            capture_output=True, text=True, check=True,
        ).stdout.strip()
        assert head_after_a == initial_sha, (
            f"Phase A must NOT advance HEAD; got {head_after_a} vs {initial_sha}"
        )
        status_after_a = subprocess.run(
            ["git", "-C", str(repo_root), "status", "--porcelain"],
            capture_output=True, text=True, check=True,
        ).stdout
        assert "dirty.txt" in status_after_a, (
            "Phase A: dirty tree must remain dirty after blocked bulk"
        )
        # No bulk-commit sentinel was written
        leftover = list(pathlib.Path(tmp).glob("claude-bulk-commit-sentinel-*.json"))
        assert leftover == [], f"Phase A: sentinel must not be written; found {leftover}"
        # No push-gate token written
        push_dir = tmp_root / "agentic-commit" / "push"
        assert not push_dir.exists(), (
            "Phase A: no push-gate token must exist (no real commit produced)"
        )
        # No Step 7 markers emitted
        assert "STEP7_" not in proc_a.stderr, (
            f"Phase A: no STEP7_ markers expected; stderr={proc_a.stderr!r}"
        )

        # ----- Phase B: non-bulk /commit <task-id> fallback on SAME dirty tree -----
        # 1. Simulate changelog-analyst Phase 5 (commit creation)
        new_sha = _make_changelog_commit(repo_root, task_id)
        assert new_sha != initial_sha, "Phase B: new commit SHA must differ"
        head_after_b_commit = subprocess.run(
            ["git", "-C", str(repo_root), "rev-parse", "HEAD"],
            capture_output=True, text=True, check=True,
        ).stdout.strip()
        assert head_after_b_commit == new_sha
        # Tree must now be clean (the dirty.txt was committed)
        status_after_b_commit = subprocess.run(
            ["git", "-C", str(repo_root), "status", "--porcelain"],
            capture_output=True, text=True, check=True,
        ).stdout.strip()
        assert status_after_b_commit == "", (
            f"Phase B: tree must be clean post-commit; got: {status_after_b_commit!r}"
        )

        # 2. Simulate changelog-analyst Phase 6 (push-gate token write at canonical path)
        push_gate = _canonical_push_gate_path(repo_root, "main", tmp_root)
        _write_push_gate_token(push_gate, new_sha)
        assert push_gate.is_file()
        gate_payload = json.loads(push_gate.read_text(encoding="utf-8"))
        assert gate_payload["commit_sha"] == new_sha, (
            "Push-gate token commit_sha must match real HEAD SHA"
        )

        # 3. Simulate changelog-analyst structured-output JSON
        cl_status = _simulate_changelog_analyst_structured_output(new_sha)
        assert cl_status["commit_status"] == "committed"

        # 4. Set up dev-docs (context.spec_path) for stage-1 dispatch
        spec_file = specs_dir / "spec-20260525-053200.md"
        spec_file.write_text(
            f"# Continuation spec\n<!-- spec-continuation-of: {task_id} -->\n",
            encoding="utf-8",
        )
        rel_spec_path = spec_file.relative_to(tmp_root)
        _write_dev_docs(
            dev_docs_root, task_id,
            context_spec_path=str(rel_spec_path),
            close_report_continuation=None,
        )

        # 5. Execute commit.md Step 7 via reference harness
        proc_b = _run_step7(task_id, dev_docs_root, push_gate,
                            changelog_status=cl_status["commit_status"])
        assert proc_b.returncode == 0, (
            f"Step 7 must succeed; stderr={proc_b.stderr!r}"
        )
        assert "STEP7_SPEC_CONTINUE_DISPATCHED" in proc_b.stderr, (
            f"Phase B: dispatch marker missing from stderr={proc_b.stderr!r}"
        )
        assert f"task-id={task_id}" in proc_b.stderr
        assert "stage=1" in proc_b.stderr
        assert "STEP7_SKIPPED" not in proc_b.stderr, (
            f"Phase B: no SKIP markers expected; stderr={proc_b.stderr!r}"
        )


