        new_sha = _make_changelog_commit(repo_root, task_id)
        push_gate = _canonical_push_gate_path(repo_root, "main", tmp_root)
        _write_push_gate_token(push_gate, new_sha)

        spec_file = specs_dir / "spec-20260525-053300.md"
        spec_file.write_text(
            f"# Parity spec\n<!-- spec-continuation-of: {task_id} -->\n",
            encoding="utf-8",
        )
        rel_spec_path = spec_file.relative_to(tmp_root)
        _write_dev_docs(dev_docs_root, task_id,
                        context_spec_path=str(rel_spec_path),
                        close_report_continuation=None)

        def _run(trace_on: bool):
            env = os.environ.copy()
            if trace_on:
                env["COMMIT_STEP7_TRACE"] = "1"
            else:
                env.pop("COMMIT_STEP7_TRACE", None)
            return subprocess.run(
                [sys.executable, str(STEP7_HARNESS),
                 "--task-id", task_id,
                 "--dev-docs-root", str(dev_docs_root),
                 "--changelog-status", "committed",
                 "--push-gate-token-path", str(push_gate)],
                capture_output=True, text=True, env=env, timeout=15,
            )

        off = _run(trace_on=False)
        on = _run(trace_on=True)

        # Exit code identical
        assert off.returncode == on.returncode == 0, (
            f"Exit code mismatch: off={off.returncode} on={on.returncode}"
        )
        # Stdout identical
        assert off.stdout == on.stdout, (
            f"Trace must not affect stdout.\n"
            f"off: {off.stdout!r}\non:  {on.stdout!r}"
        )
        # Stderr: trace-off has NO STEP7_ markers; trace-on does
        assert "STEP7_" not in off.stderr, (
            f"trace-off must emit no STEP7_ markers; got {off.stderr!r}"
        )
        assert "STEP7_SPEC_CONTINUE_DISPATCHED" in on.stderr, (
            f"trace-on must emit STEP7_SPEC_CONTINUE_DISPATCHED; got {on.stderr!r}"
        )
